user_prompt:
[
  {
    "id": 0,
    "text": "プロセカアフタートークほどけぬ明日に手を伸ばしてへん。"
  },
  {
    "id": 1,
    "text": "イエーイ。"
  },
  {
    "id": 2,
    "text": "皆さんこんばんは。"
  },
  {
    "id": 3,
    "text": "25時ナイトコードで秋山水希役の佐藤日向です。"
  },
  {
    "id": 4,
    "text": "このプロセカアフタートークは皆さんから頂いたお便りを紹介しながらイベントを振り返る配信となっております。"
  },
  {
    "id": 5,
    "text": "え、今回はほどけぬ明日に手を伸ばしてへんとなっています。"
  },
  {
    "id": 6,
    "text": "皆様、ストーリーはお楽しみいただけましたでしょうか?"
  },
  {
    "id": 7,
    "text": "ちょうどね、昨日までやっていたイベントなんですけれどもどうでしたかね、"
  },
  {
    "id": 8,
    "text": "みんな?"
  },
  {
    "id": 9,
    "text": "楽しんでくれてたらいいなと思うんですけれども、"
  },
  {
    "id": 10,
    "text": "結構ね、あのにずき自身が将来何をしたいかっていう未来に向けてこう向き合う、"
  },
  {
    "id": 11,
    "text": "あの、お話になっていたんじゃないかなと思うので、"
  },
  {
    "id": 12,
    "text": "もしかしたらね、あの進学とか進路とか決めなきゃいけない時期の子とかはなんかちょっと刺さる部分があるストーリーになっていたんじゃないかななんていう風に思います。"
  },
  {
    "id": 13,
    "text": "はい、え、4月からアフタートークがプチリニューアルしまして、"
  },
  {
    "id": 14,
    "text": "事前にプロス、プロセカ公式Discordとメールにてアフタートークのお便りを募集させていただきました。"
  },
  {
    "id": 15,
    "text": "皆さん、お便り送っていただいてありがとうございます。"
  },
  {
    "id": 16,
    "text": "え、皆さんから頂いたお便りを番組内で紹介させていただきますので、"
  },
  {
    "id": 17,
    "text": "お楽しみに。"
  },
  {
    "id": 18,
    "text": "またイベントやこの配信、放送をね、え、乾燥していただく、"
  },
  {
    "id": 19,
    "text": "乾燥を呟いていただく場合は、ハッシュタグ、プロセカアフタートークでポストしてください。"
  },
  {
    "id": 20,
    "text": "え、YouTubeのチャットも見ていますし、え、ハッシュタグも後ほど見させていただきますので、"
  },
  {
    "id": 21,
    "text": "え、気になるコメントどんどん拾っていこうかなと思います。"
  },
  {
    "id": 22,
    "text": "思ったよりね、海外のコメントばっかりでね、あの、日本語のコメントが全然見当たらないですけれどもリボン可愛いとか水希とお揃いの髪型で可愛いとかああ、"
  },
  {
    "id": 23,
    "text": "今のターンちょっとまだ配信がね、多分遅れてるから、"
  },
  {
    "id": 24,
    "text": "あの、髪型と服のことに触れてくれてますね。"
  },
  {
    "id": 25,
    "text": "今日、今回はね、あの、ちゃんと、あのイラストを意識して、"
  },
  {
    "id": 26,
    "text": "今回はってかいつもですけどと、いや、いつと意識してきました。"
  },
  {
    "id": 27,
    "text": "こんばんは、こんばんは。"
  },
  {
    "id": 28,
    "text": "みんなありがとうございます。"
  },
  {
    "id": 29,
    "text": "あ、ストーリーも書き下ろし楽曲も良くて号泣しました。"
  },
  {
    "id": 30,
    "text": "曲のこと後ほど触れます。"
  },
  {
    "id": 31,
    "text": "私ももうね何ですか、あれはって家で言いましたよ。"
  },
  {
    "id": 32,
    "text": "何ですか、これはって。"
  },
  {
    "id": 33,
    "text": "なんかすごい、あの、企業努力を感じました。"
  },
  {
    "id": 34,
    "text": "はい、はい、はい。"
  },
  {
    "id": 35,
    "text": "そんな話は後でさせていただこうかなと思います。"
  },
  {
    "id": 36,
    "text": "え、それではね、早速今回の届けぬ明日に手を伸ばしてのストーリーについてお話していこうと思います。"
  },
  {
    "id": 37,
    "text": "ます。"
  },
  {
    "id": 38,
    "text": "え、皆さん今回のストーリーについてもね、お便りいただいてますので、"
  },
  {
    "id": 39,
    "text": "え、紹介しながら一緒にストーリーを振り返っていけたらなと思います。"
  },
  {
    "id": 40,
    "text": "まずね、え、小鳥のママさんからいただいたお便りです。"
  },
  {
    "id": 41,
    "text": "え、日奈津さんコニーゴです。"
  },
  {
    "id": 42,
    "text": "コニーゴ。"
  },
  {
    "id": 43,
    "text": "え、親子でプロセカ楽しませてもらっています。"
  },
  {
    "id": 44,
    "text": "さよしの水希ちゃんバナー最高に可愛くて面白くて感動しました。"
  },
  {
    "id": 45,
    "text": "今までの体験や周りの人たちとの関わりで、"
  },
  {
    "id": 46,
    "text": "え、水希ちゃんの様々な思いに触れられることができて良かったと思っています。"
  },
  {
    "id": 47,
    "text": "自分らしく自分の好きなものを諦めないで続けていくことって迷ったり壁に当たったり大変なことだと思います。"
  },
  {
    "id": 48,
    "text": "それでもその思いを持ち続けていればいつか報われる時が来ると思っています。"
  },
  {
    "id": 49,
    "text": "2後のみんなのようにありのままの自分を見てくれている人、"
  },
  {
    "id": 50,
    "text": "認めてくれる人ってのは絶対いると思っています。"
  },
  {
    "id": 51,
    "text": "プロセカのストーリー本当に大好きです。"
  },
  {
    "id": 52,
    "text": "日向さん、いつも声を当ててくださり本当にありがとうございます。"
  },
  {
    "id": 53,
    "text": "これからも水希ちゃんと日向さんを全力で押させていただきますということで、"
  },
  {
    "id": 54,
    "text": "ことりのままさん、ありがとうございます。"
  },
  {
    "id": 55,
    "text": "いや、今回はまずお姉ちゃんが海外からお家に帰ってきてくれるっていうのは、"
  },
  {
    "id": 56,
    "text": "そのポップアップショップをやるっていうところから始まって、その25のみんなとお姉ちゃんをに会ってもらいたいって水希が思ってることがすごく水希にとってはまず全身だなと私はすごく思いましたし、"
  },
  {
    "id": 57,
    "text": "あの、これまでね、あの、金デトマフヨはゆうきさんに会ったことあったけど、"
  },
  {
    "id": 58,
    "text": "えながね、今回初めて会えたりとか、色々ね、あの、"
  },
  {
    "id": 59,
    "text": "お話も進んでいたりはするんですけど、"
  },
  {
    "id": 60,
    "text": "やっぱ中でもま、なんか水希が今好きでやってることって動画を作ることもそうだけど、"
  },
  {
    "id": 61,
    "text": "そのお洋服をリメイクしたりとか、お洋服屋さん見に行ったりとかコスメ見たりとかそういう好きなことがいっぱいある子だからこそ、"
  },
  {
    "id": 62,
    "text": "じゃ、それを自分が将来何かをするってなった時に自分が目指したいものって何だろうって、"
  },
  {
    "id": 63,
    "text": "この時点で向き合ってるのってすごいなと私は思っていてもう、"
  },
  {
    "id": 64,
    "text": "ね、私なんて大学行く時なんてお金払うだたら、"
  },
  {
    "id": 65,
    "text": "ちゃんと手に食がつけられる、手元に残るものを勉強しなければ意味がないと思いながらオープンキャンパスをひたすら回ってたもんだから、"
  },
  {
    "id": 66,
    "text": "なんか結構水希とは入り方、好きなものの探し方の入り方が全然違うななんていう風にね、"
  },
  {
    "id": 67,
    "text": "思ってたんですけど、その中でなんかこうゆっくりではありつつ、"
  },
  {
    "id": 68,
    "text": "水希のスピードではありつつ、自分の好きを見つめ直すことができる時間だったと思いますし、"
  },
  {
    "id": 69,
    "text": "それってすごく大切なことだなと私は思ったのでなんかこう水希にとってお姉ちゃんが出したポップアップショップだけじゃなくて、"
  },
  {
    "id": 70,
    "text": "そのお洋服に触れることが自分の中でそれがただの好きじゃなくて好きを職にしたいかもしれない。"
  },
  {
    "id": 71,
    "text": "って思えることって結構大きいことだなと思うのでなんか笑ってくれて良かったなと私は思いました。"
  }
]

response_parts.content:
{
  "response": [
    {
      "id": 0,
      "translated": "Welcome to ProSeka AfterTalk for the event \"Reaching Out to an Unraveling Tomorrow.\""
    },
    {
      "id": 1,
      "translated": "Yay!"
    },
    {
      "id": 2,
      "translated": "Good evening, everyone."
    },
    {
      "id": 3,
      "translated": "I'm Hinata Sato, the voice of Mizuki Akiyama from Nightcord at 25:00."
    },
    {
      "id": 4,
      "translated": "ProSeka AfterTalk is a stream where we look back on the event while reading letters from all of you."
    },
    {
      "id": 5,
      "translated": "This time, we're focusing on \"Reaching Out to an Unraveling Tomorrow.\""
    },
    {
      "id": 6,
      "translated": "Did you all enjoy the story?"
    },
    {
      "id": 7,
      "translated": "The event just ended yesterday. How was it for everyone?"
    },
    {
      "id": 8,
      "translated": "What did you think?"
    },
    {
      "id": 9,
      "translated": "I hope you all enjoyed it."
    },
    {
      "id": 10,
      "translated": "It was a story where Mizuki really faced their future and thought about what they want to do."
    },
    {
      "id": 11,
      "translated": "I think it was a very meaningful chapter."
    },
    {
      "id": 12,
      "translated": "For those of you at an age where you have to decide on your education or career path, parts of this story might have really hit home."
    },
    {
      "id": 13,
      "translated": "Also, AfterTalk had a mini-renewal in April."
    },
    {
      "id": 14,
      "translated": "We've been collecting your messages in advance via the official ProSeka Discord and email."
    },
    {
      "id": 15,
      "translated": "Thank you so much to everyone who sent one in."
    },
    {
      "id": 16,
      "translated": "I'll be reading some of your letters during the show,"
    },
    {
      "id": 17,
      "translated": "so please look forward to that."
    },
    {
      "id": 18,
      "translated": "If you want to post your impressions of the event or this stream,"
    },
    {
      "id": 19,
      "translated": "please use the hashtag #ProSekaAfterTalk."
    },
    {
      "id": 20,
      "translated": "I'm keeping an eye on the YouTube chat and I'll check the hashtag later too,"
    },
    {
      "id": 21,
      "translated": "so I'll try to pick out some interesting comments."
    },
    {
      "id": 22,
      "translated": "There are more international comments than I expected! I can't find many in Japanese. \"Your ribbon is cute,\" \"Your hair matches Mizuki's...\""
    },
    {
      "id": 23,
      "translated": "The stream is probably a bit delayed for you right now,"
    },
    {
      "id": 24,
      "translated": "but I see people mentioning my hair and outfit."
    },
    {
      "id": 25,
      "translated": "I tried to match the card illustration for today."
    },
    {
      "id": 26,
      "translated": "Well, I always try to, but I was especially conscious of it this time."
    },
    {
      "id": 27,
      "translated": "Good evening! Hello everyone."
    },
    {
      "id": 28,
      "translated": "Thank you all for being here."
    },
    {
      "id": 29,
      "translated": "Oh, someone said, \"The story and the new song were so good I sobbed.\""
    },
    {
      "id": 30,
      "translated": "I'll talk about the song later."
    },
    {
      "id": 31,
      "translated": "When I saw it at home, I was like, \"What is this?!\""
    },
    {
      "id": 32,
      "translated": "In a good way! I was just stunned."
    },
    {
      "id": 33,
      "translated": "I really felt the incredible effort the team put into it."
    },
    {
      "id": 34,
      "translated": "Yes, exactly."
    },
    {
      "id": 35,
      "translated": "But we'll save that talk for later."
    },
    {
      "id": 36,
      "translated": "So, let's dive right into the story of \"Reaching Out to an Unraveling Tomorrow.\""
    },
    {
      "id": 37,
      "translated": "Here we go."
    },
    {
      "id": 38,
      "translated": "We received letters about this story as well,"
    },
    {
      "id": 39,
      "translated": "so I'd like to look back on the events while reading them."
    },
    {
      "id": 40,
      "translated": "[CORNER: Fan Letter Corner] First, we have a letter from Kotori no Mama."
    },
    {
      "id": 41,
      "translated": "\"Hello, Hinata-san! Ko-Niigo!\""
    },
    {
      "id": 42,
      "translated": "Ko-Niigo!"
    },
    {
      "id": 43,
      "translated": "\"My child and I enjoy playing ProSeka together.\""
    },
    {
      "id": 44,
      "translated": "\"Mizuki-chan's banner was incredibly cute, interesting, and moving.\""
    },
    {
      "id": 45,
      "translated": "\"Through their past experiences and interactions with those around them,\""
    },
    {
      "id": 46,
      "translated": "\"I'm glad we got to see so many of Mizuki-chan's different feelings.\""
    },
    {
      "id": 47,
      "translated": "\"I think staying true to yourself and not giving up on what you love can be hard when you face obstacles.\""
    },
    {
      "id": 48,
      "translated": "\"But I believe that if you hold onto those feelings, a time will come when they are rewarded.\""
    },
    {
      "id": 49,
      "translated": "\"Just like the members of Niigo, there are definitely people out there\""
    },
    {
      "id": 50,
      "translated": "\"who will see and accept you for who you truly are.\""
    },
    {
      "id": 51,
      "translated": "\"I really love the stories in ProSeka.\""
    },
    {
      "id": 52,
      "translated": "\"Hinata-san, thank you so much for always voicing them.\""
    },
    {
      "id": 53,
      "translated": "\"I'll continue to support both you and Mizuki-chan with all my heart.\""
    },
    {
      "id": 54,
      "translated": "Thank you so much, Kotori no Mama."
    },
    {
      "id": 55,
      "translated": "In this story, Mizuki's sister comes home from abroad."
    },
    {
      "id": 56,
      "translated": "It starts with the pop-up shop, and I felt it was a huge step forward for Mizuki to want their sister to meet the rest of Niigo."
    },
    {
      "id": 57,
      "translated": "Kanade and Mafuyu had met Yuuki-san before,"
    },
    {
      "id": 58,
      "translated": "but Ena met her for the first time here. The story really progressed in many ways."
    },
    {
      "id": 59,
      "translated": "There was a lot of development."
    },
    {
      "id": 60,
      "translated": "Mizuki loves making videos, but they also love things like"
    },
    {
      "id": 61,
      "translated": "remaking clothes, visiting boutiques, and looking at makeup. They have so many things they love."
    },
    {
      "id": 62,
      "translated": "So, when it comes to what they want to do in the future, thinking about what they want to aim for..."
    },
    {
      "id": 63,
      "translated": "I think it's amazing that they're already facing those questions at this stage."
    },
    {
      "id": 64,
      "translated": "When I was going to college, I just thought that if I was paying for it,"
    },
    {
      "id": 65,
      "translated": "I had to study something that would give me a practical skill. I spent all my time at open campuses thinking like that."
    },
    {
      "id": 66,
      "translated": "So, my approach to finding what I liked was completely different from Mizuki's."
    },
    {
      "id": 67,
      "translated": "Even so, I think this was a time for Mizuki to re-examine what they love,"
    },
    {
      "id": 68,
      "translated": "at their own pace. That's such an important thing to do."
    },
    {
      "id": 69,
      "translated": "It wasn't just about their sister's pop-up shop."
    },
    {
      "id": 70,
      "translated": "Being around those clothes helped them realize that it's not just a hobby—they might want to make it their career."
    },
    {
      "id": 71,
      "translated": "Realizing that is a huge deal, so I was just really happy to see them smiling."
    }
  ]
}

user_prompt:
[
  {
    "id": 0,
    "text": "はい、ということでね、え、今回も私が個人的に語りたいシーンをピックアップさせていただきましたので、"
  },
  {
    "id": 1,
    "text": "一緒に見ていけたらと思います。"
  },
  {
    "id": 2,
    "text": "こちらです。"
  },
  {
    "id": 3,
    "text": "素晴らしい。"
  },
  {
    "id": 4,
    "text": "いい話。"
  },
  {
    "id": 5,
    "text": "本当にいい話。"
  },
  {
    "id": 6,
    "text": "って思います、私は。"
  },
  {
    "id": 7,
    "text": "自分がね、もう進路を選択した身ではあるからこそ、"
  },
  {
    "id": 8,
    "text": "こう誰かが選択する瞬間みたいなのに、ま、"
  },
  {
    "id": 9,
    "text": "立ち合うというか、ま、イベントストーリーという形でですけど、"
  },
  {
    "id": 10,
    "text": "ていう時にやっぱりなんかこうここで自分の選択合ってるのかなって思う瞬間さんて絶対あるからでもなんかそれが10年後、"
  },
  {
    "id": 11,
    "text": "20年後の自分にとって、あの時この選択取って良かったなって思えてたらそれはきっとあれ、"
  },
  {
    "id": 12,
    "text": "いいことだと思うんですけど、そこに伴ってくるのってやっぱり努力だと思うので、"
  },
  {
    "id": 13,
    "text": "努力が必要なことに関しては選択に合ってる間違ってるも私はないなと思うので、"
  },
  {
    "id": 14,
    "text": "努力が伴った選択っていうのはきっと1年とか2年とかではね、"
  },
  {
    "id": 15,
    "text": "ああ、これやんなきゃ良かったなってもしかしたら思う時が来るのかもしれないけど、"
  },
  {
    "id": 16,
    "text": "10年ね、20年って見た時には、それがね、"
  },
  {
    "id": 17,
    "text": "結果的にね繋がってる時も絶対あると思うし、"
  },
  {
    "id": 18,
    "text": "こん時これやってなかったら今これできてないもんなとか、"
  },
  {
    "id": 19,
    "text": "同じ職業じゃなくてもきっと思うことってあると思うので、"
  },
  {
    "id": 20,
    "text": "今努力してるもの、努力したいものがある子は是非続けてもらったり、"
  },
  {
    "id": 21,
    "text": "あの、やるっていう決意をしてもらえるっていうきっかけになるイベントストーリーになっていたらいいなと私は思うイベントストーリーでございました。"
  },
  {
    "id": 22,
    "text": "ということでね、え、ここからはイラストについてお話ししていこうと思います。"
  },
  {
    "id": 23,
    "text": "ではお便り紹介させてください。"
  },
  {
    "id": 24,
    "text": "飯さん、飯さんからいただきましたお便りです。"
  },
  {
    "id": 25,
    "text": "ありがとうございます。"
  },
  {
    "id": 26,
    "text": "え、佐藤さん、こんにご。"
  },
  {
    "id": 27,
    "text": "え、いつも楽しくプロセカをプレイさせてもらっています。"
  },
  {
    "id": 28,
    "text": "え、今回の星4イラスト、特に水キイラストがとても良くて必死でガチャを回し手に入れました。"
  },
  {
    "id": 29,
    "text": "今回のイラストもシークレットディスタンスや軽曲の道はいずこへ。"
  },
  {
    "id": 30,
    "text": "どこへ?"
  },
  {
    "id": 31,
    "text": "いずこへ。"
  },
  {
